class Solution:
    def repeatedCharacter(self, s):
        # Independent: for each character, find the index of its second occurrence,
        # then pick the character whose second-occurrence index is smallest.
        best_idx = None
        best_ch = ''
        for ch in set(s):
            positions = [i for i, c in enumerate(s) if c == ch]
            if len(positions) >= 2:
                second = positions[1]
                if best_idx is None or second < best_idx:
                    best_idx = second
                    best_ch = ch
        return best_ch

